import requests
from django.conf import settings
from decimal import Decimal


class PayPalService:
    """
    Servicio para integración con PayPal Sandbox.
    """

    def __init__(self):
        self.sandbox_mode = settings.PAYPAL_SANDBOX_MODE
        self.client_id = settings.PAYPAL_CLIENT_ID
        self.client_secret = settings.PAYPAL_CLIENT_SECRET

        if self.sandbox_mode:
            self.base_url = 'https://api.sandbox.paypal.com'
        else:
            self.base_url = 'https://api.paypal.com'

    def get_access_token(self):
        """
        Obtiene un token de acceso de PayPal.
        """
        url = f'{self.base_url}/v1/oauth2/token'
        headers = {'Accept': 'application/json', 'Accept-Language': 'en_US'}
        data = {'grant_type': 'client_credentials'}

        try:
            response = requests.post(
                url,
                headers=headers,
                data=data,
                auth=(self.client_id, self.client_secret),
                timeout=10
            )
            response.raise_for_status()
            return response.json().get('access_token')
        except Exception as e:
            print(f'Error obteniendo token de PayPal: {e}')
            return None

    def crear_pago(self, reserva, return_url, cancel_url):
        """
        Crea un pago en PayPal.
        """
        token = self.get_access_token()
        if not token:
            return None

        url = f'{self.base_url}/v1/payments/payment'
        headers = {
            'Content-Type': 'application/json',
            'Authorization': f'Bearer {token}'
        }

        data = {
            'intent': 'sale',
            'payer': {
                'payment_method': 'paypal'
            },
            'transactions': [
                {
                    'amount': {
                        'total': str(reserva.importe_total),
                        'currency': 'EUR',
                        'details': {
                            'subtotal': str(reserva.importe_total)
                        }
                    },
                    'description': f'Reserva de {reserva.barco.nombre}',
                    'invoice_number': reserva.codigo_seguimiento
                }
            ],
            'redirect_urls': {
                'return_url': return_url,
                'cancel_url': cancel_url
            }
        }

        try:
            response = requests.post(
                url,
                json=data,
                headers=headers,
                timeout=10
            )
            response.raise_for_status()
            return response.json()
        except Exception as e:
            print(f'Error creando pago en PayPal: {e}')
            return None

    def ejecutar_pago(self, payment_id, payer_id):
        """
        Ejecuta un pago en PayPal.
        """
        token = self.get_access_token()
        if not token:
            return None

        url = f'{self.base_url}/v1/payments/payment/{payment_id}/execute'
        headers = {
            'Content-Type': 'application/json',
            'Authorization': f'Bearer {token}'
        }

        data = {'payer_id': payer_id}

        try:
            response = requests.post(
                url,
                json=data,
                headers=headers,
                timeout=10
            )
            response.raise_for_status()
            return response.json()
        except Exception as e:
            print(f'Error ejecutando pago en PayPal: {e}')
            return None

from django.shortcuts import render, redirect, get_object_or_404
