def obtener_sesion_id(request):
    if not request.session.session_key:
        request.session.create()
    return request.session.session_key


class CartView(View):
    def get(self, request):
        sesion_id = obtener_sesion_id(request)
        items = ItemCesta.objects.filter(sesion_id=sesion_id)

        total = Decimal('0.00')
        for item in items:
            precio_item = calcular_precio_reserva(
                item.barco,
                item.fecha_inicio,
                item.fecha_fin,
                item.cantidad
            )
            total += precio_item

        context = {
            'items': items,
            'total': total,
        }
        return render(request, 'reservations/cart.html', context)


class AddToCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        barco = get_object_or_404(Barco, id=barco_id)
        form = AgregarAcestaForm(request.POST)

        if form.is_valid():
            sesion_id = obtener_sesion_id(request)
            cantidad = form.cleaned_data['cantidad']
            fecha_inicio = form.cleaned_data['fecha_inicio']
            fecha_fin = form.cleaned_data['fecha_fin']

            item, created = ItemCesta.objects.get_or_create(
                sesion_id=sesion_id,
                barco=barco,
                fecha_inicio=fecha_inicio,
                fecha_fin=fecha_fin,
                defaults={'cantidad': cantidad}
            )

            if not created:
                item.cantidad += cantidad
                item.save()

            messages.success(request, f'{barco.nombre} añadido a la cesta.')
            return redirect('reservations:cart')

        return redirect('catalog:barco_detail', id=barco_id)


class UpdateCartView(View):
    def post(self, request):
        item_id = request.POST.get('item_id')
        cantidad = request.POST.get('cantidad')

        try:
            item = ItemCesta.objects.get(id=item_id)
            if int(cantidad) > 0:
                item.cantidad = int(cantidad)
                item.save()
            else:
                item.delete()
            messages.success(request, 'Cesta actualizada.')
        except (ItemCesta.DoesNotExist, ValueError):
            messages.error(request, 'Error al actualizar la cesta.')

        return redirect('reservations:cart')


class ClearCartView(View):
    def post(self, request):
        sesion_id = obtener_sesion_id(request)
        ItemCesta.objects.filter(sesion_id=sesion_id).delete()
        messages.success(request, 'Cesta vaciada.')
        return redirect('reservations:cart')


class ReservationStep1View(View):
