        return redirect('reservations:track') + f'?codigo={codigo}'


class PayPalReturnView(View):
    def get(self, request):
        payment_id = request.session.get('payment_id')
        payer_id = request.GET.get('PayerID')
        reserva_id = request.session.get('reserva_id')

        if not payment_id or not payer_id or not reserva_id:
            messages.error(request, 'Error en la confirmación del pago.')
            return redirect('reservations:step3')

        try:
            reserva = Reserva.objects.get(id=reserva_id)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('reservations:cart')

        paypal_service = PayPalService()
        resultado = paypal_service.ejecutar_pago(payment_id, payer_id)

        if resultado and resultado.get('state') == 'approved':
            reserva.estado = 'PAGADO'
            reserva.transaccion_paypal = payment_id
            reserva.save()

            CambioEstadoReserva.objects.create(
                reserva=reserva,
                estado_anterior='PENDIENTE_DE_PAGO',
                estado_nuevo='PAGADO',
                usuario=request.user if request.user.is_authenticated else None,
            )

            ItemCesta.objects.filter(sesion_id=obtener_sesion_id(request)).delete()
            request.session.flush()

            messages.success(request, 'Pago realizado exitosamente.')
            return redirect('reservations:confirmation')
        else:
            messages.error(request, 'Error al procesar el pago en PayPal.')
            return redirect('reservations:step3')


class PayPalCancelView(View):
    def get(self, request):
        messages.warning(request, 'Pago cancelado.')
        return redirect('reservations:step3')


class MyReservationsView(View):
    @method_decorator(login_required)
    def get(self, request):
        reservas = Reserva.objects.filter(cliente=request.user)
        context = {'reservas': reservas}
        return render(request, 'reservations/my_reservations.html', context)


class CancelReservationView(View):
    @method_decorator(login_required)
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id, cliente=request.user)

        if reserva.estado in ['EN_USO', 'DEVUELTO']:
            messages.error(request, 'No se puede cancelar una reserva en uso o devuelta.')
        else:
            reserva.estado = 'CANCELADA'
            reserva.save()
            messages.success(request, 'Reserva cancelada.')

        return redirect('reservations:my_reservations')

